import client from "./client";

/**
 * Fetch the list of all analysis sessions as history entries.
 * @param {string} [sessionId] - Optional session ID from sessionStorage to filter results.
 * @returns {Promise<{ data: { history: Array<{ id, idea, completedAt, competitorCount, status }> } }>}
 */
export const getAnalysisHistory = (sessionId) =>
  client.get("/market-research", { params: sessionId ? { sessionId } : {} });

/**
 * Called once when user logs in — persists local session data under their account.
 * @param {string} sessionId - UUID generated by the frontend (from sessionStorage)
 * @param {string} idea - The startup idea text
 * @param {Object} state - The full analysis state to persist
 */
export const saveMarketResearchSession = (sessionId, idea, state) =>
  client.put(`/market-research/${sessionId}`, { idea, state });

/**
 * Retrieve a stored analysis by session ID.
 */
export const getMarketResearchSession = (sessionId) =>
  client.get(`/market-research/${sessionId}`);

/**
 * Queue an AI market research task for the given session.
 * @param {string} sessionId
 * @param {string} idea
 * @param {number} numCompetitors - How many competitors to analyze (plan-dependent)
 * @param {string[]|null} regions - null for Worldwide, array of country codes otherwise
 */
export const requestMarketResearchAnalysis = (
  sessionId,
  idea,
  numCompetitors,
  regions,
) =>
  client.post(`/market-research/${sessionId}/analyze`, {
    idea,
    numCompetitors,
    regions: regions ?? null,
  });

/**
 * Retrieve the AI-generated report once the task has completed.
 * @param {string} sessionId
 */
export const getMarketResearchReport = (sessionId) =>
  client.get(`/market-research/${sessionId}/report`);

/**
 * Retrieve a single competitor's detailed profile (written by the agent).
 * @param {string} sessionId
 * @param {string} competitorId
 */
export const getCompetitorDetails = (sessionId, competitorId) =>
  client.get(`/market-research/${sessionId}/competitors/${competitorId}`);
